import React from 'react';
import { Routes, Route } from 'react-router-dom';
// Import your components here

function App() {
  return (
    <div className="min-h-screen bg-gray-100">
      <header className="bg-white shadow-md">
        <div className="container mx-auto px-4 py-4">
          <h1 className="text-2xl font-bold text-blue-600">ElderFit</h1>
        </div>
      </header>
      
      <main className="container mx-auto px-4 py-8">
        <div className="bg-white rounded-lg shadow-lg p-6 mb-8">
          <h2 className="text-xl font-semibold text-gray-800 mb-4">Welcome to ElderFit</h2>
          <p className="text-gray-600">Your personalized fitness companion for healthier aging</p>
          <button className="btn btn-primary mt-4">Get Started</button>
        </div>
        
        <Routes>
          {/* Your routes go here */}
          <Route path="/" element={<div className="text-green-500 font-bold">Home Page</div>} />
          {/* Add more routes as needed */}
        </Routes>
      </main>
    </div>
  );
}

export default App;
